What vulnerability exists in this staking contract?

```solidity
pragma solidity ^0.8.0;

contract StakingPool {
    uint256 public rewardPerTokenStored;
    uint256 public lastUpdateTime;
    uint256 public rewardRate = 1e18; // per second
    uint256 public totalStaked;

    mapping(address => uint256) public userRewardPerTokenPaid;
    mapping(address => uint256) public rewards;
    mapping(address => uint256) public stakedBalance;

    function stake(uint256 amount) external {
        totalStaked += amount;
        stakedBalance[msg.sender] += amount;
        lastUpdateTime = block.timestamp;
        rewardPerTokenStored = 0;
    }
}
```

assistant:
**Vulnerability: Staking Reward Accounting Reset on Every Stake**

The `stake` function resets `lastUpdateTime = block.timestamp` and `rewardPerTokenStored = 0` whenever *any* user stakes. This wipes out accrued-but-unclaimed rewards for all existing stakers — they lose their pending rewards every time a new deposit occurs.

**Fix**: follow the standard synthetix-style reward accounting pattern: calculate the accrued `rewardPerToken` as of the current timestamp before updating state, snapshot it per user at the time of their action, and only update `lastUpdateTime` to `block.timestamp` without zeroing `rewardPerTokenStored`:
```solidity
function rewardPerToken() public view returns (uint256) {
    if (totalStaked == 0) return rewardPerTokenStored;
    return rewardPerTokenStored + rewardRate * (block.timestamp - lastUpdateTime) * 1e18 / totalStaked;
}

modifier updateReward(address account) {
    rewardPerTokenStored = rewardPerToken();
    lastUpdateTime = block.timestamp;
    rewards[account] += (rewardPerToken() - userRewardPerTokenPaid[account]) * stakedBalance[account] / 1e18;
    userRewardPerTokenPaid[account] = rewardPerToken();
    _;
}
```

