assistant:
**Fixed — add ReentrancyGuard and apply CEI pattern:**

```solidity
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Bank is ReentrancyGuard {
    mapping(address => uint256) public balances;

    function deposit() external payable {
        balances[msg.sender] += msg.value;
    }

    function transfer(address to, uint256 amount) external nonReentrant {
        require(balances[msg.sender] >= amount, "Insufficient");
        balances[msg.sender] -= amount;   // effect first
        balances[to] += amount;            // effect first
        (bool ok, ) = msg.sender.call{value: amount}("");
        require(ok, "Transfer failed");
    }
}
```

**Changes**:
- `nonReentrant` modifier blocks any reentrant call (including calls to `transfer` itself or to `deposit`) while the function is executing.
- CEI order: deduct `balances[msg.sender]` and credit `balances[to]` *before* the external call, so even if the guard were removed, balances are correct.

